PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE IF NOT EXISTS "business_categories" (
	`id` text PRIMARY KEY NOT NULL,
	`name` text NOT NULL,
	`slug` text NOT NULL,
	`description` text,
	`icon` text DEFAULT '',
	`parent_id` text,
	`entity_type` text DEFAULT 'business',
	`created_at` integer DEFAULT (strftime('%s', 'now')),
	`updated_at` integer DEFAULT (strftime('%s', 'now'))
, form_fields TEXT, sort_order INTEGER DEFAULT 0, is_active INTEGER DEFAULT 1);
CREATE TABLE `site_settings` (
	`id` text PRIMARY KEY NOT NULL,
	`key` text NOT NULL,
	`value` text,
	`updated_at` integer DEFAULT (strftime('%s', 'now'))
, type TEXT DEFAULT 'string', description TEXT, is_public INTEGER DEFAULT 0);
CREATE TABLE users (
  id TEXT PRIMARY KEY NOT NULL,
  email TEXT NOT NULL UNIQUE,
  email_verified INTEGER DEFAULT 0,
  phone TEXT,
  name TEXT NOT NULL,
  image TEXT,
  role TEXT DEFAULT 'user',
  created_at INTEGER,
  updated_at INTEGER
);
CREATE TABLE sessions (
  id TEXT PRIMARY KEY NOT NULL,
  user_id TEXT NOT NULL,
  token TEXT NOT NULL UNIQUE,
  expires_at INTEGER NOT NULL,
  ip_address TEXT,
  user_agent TEXT,
  created_at INTEGER NOT NULL,
  updated_at INTEGER NOT NULL
);
CREATE TABLE accounts (
  id TEXT PRIMARY KEY NOT NULL,
  account_id TEXT NOT NULL,
  provider_id TEXT NOT NULL,
  user_id TEXT NOT NULL,
  access_token TEXT,
  refresh_token TEXT,
  id_token TEXT,
  access_token_expires_at INTEGER,
  refresh_token_expires_at INTEGER,
  scope TEXT,
  password TEXT,
  created_at INTEGER NOT NULL,
  updated_at INTEGER NOT NULL
);
CREATE TABLE verifications (
  id TEXT PRIMARY KEY NOT NULL,
  identifier TEXT NOT NULL,
  value TEXT NOT NULL,
  expires_at INTEGER NOT NULL,
  created_at INTEGER
);
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE public_sectors (
  id TEXT PRIMARY KEY,
  title TEXT NOT NULL,
  slug TEXT NOT NULL UNIQUE,
  owner_id TEXT NOT NULL,
  category_id TEXT,
  status TEXT DEFAULT 'draft',
  banner_image_id TEXT,
  profile_image_id TEXT,
  contact_name TEXT,
  contact_number TEXT,
  country_code TEXT DEFAULT '+670',
  year_of_establishment INTEGER,
  email TEXT,
  address TEXT,
  location_lat REAL,
  location_lng REAL,
  opening_hours TEXT,
  about_us TEXT,
  tags TEXT,
  likes INTEGER DEFAULT 0,
  saves INTEGER DEFAULT 0,
  rating_average REAL DEFAULT 0,
  rating_count INTEGER DEFAULT 0,
  views INTEGER DEFAULT 0,
  registration_url TEXT,
  verified_badge INTEGER DEFAULT 0,
  social_links TEXT,
  created_at INTEGER,
  updated_at INTEGER
, government_data TEXT);
CREATE TABLE non_profits (
  id TEXT PRIMARY KEY, title TEXT NOT NULL, slug TEXT NOT NULL UNIQUE,
  owner_id TEXT NOT NULL, category_id TEXT, status TEXT DEFAULT 'draft', banner_image_id TEXT, profile_image_id TEXT,
  contact_name TEXT, contact_number TEXT, country_code TEXT DEFAULT '+670',
  year_of_establishment INTEGER, email TEXT, address TEXT,
  location_lat REAL, location_lng REAL, opening_hours TEXT,
  about_us TEXT, tags TEXT,
  likes INTEGER DEFAULT 0, saves INTEGER DEFAULT 0, rating_average REAL DEFAULT 0,
  rating_count INTEGER DEFAULT 0, views INTEGER DEFAULT 0, registration_url TEXT, verified_badge INTEGER DEFAULT 0, social_links TEXT,
  created_at INTEGER, updated_at INTEGER
);
CREATE TABLE businesses(
  id TEXT,
  title TEXT,
  slug TEXT,
  owner_id TEXT,
  category_id TEXT,
  status TEXT,
  banner_image_id TEXT,
  profile_image_id TEXT,
  contact_name TEXT,
  contact_number TEXT,
  country_code TEXT,
  year_of_establishment INT,
  email TEXT,
  address TEXT,
  location_lat REAL,
  location_lng REAL,
  opening_hours TEXT,
  about_us TEXT,
  tags TEXT,
  likes INT,
  saves INT,
  rating_average REAL,
  rating_count INT,
  views INT,
  registration_url TEXT,
  verified_badge INT,
  social_links TEXT,
  created_at INT,
  updated_at INT, industry TEXT);
CREATE TABLE non_profit_categories (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  slug TEXT NOT NULL UNIQUE,
  description TEXT,
  icon TEXT DEFAULT '',
  parent_id TEXT,
  created_at INTEGER,
  updated_at INTEGER
, form_fields TEXT, sort_order INTEGER DEFAULT 0, is_active INTEGER DEFAULT 1, entity_type TEXT DEFAULT 'nonprofit');
CREATE TABLE public_sector_categories (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  slug TEXT NOT NULL UNIQUE,
  description TEXT,
  icon TEXT DEFAULT '',
  parent_id TEXT,
  created_at INTEGER,
  updated_at INTEGER
, form_fields TEXT, sort_order INTEGER DEFAULT 0, is_active INTEGER DEFAULT 1, entity_type TEXT DEFAULT 'government');
CREATE TABLE listing_categories (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  slug TEXT NOT NULL UNIQUE,
  description TEXT,
  icon TEXT DEFAULT '',
  parent_id TEXT,
  created_at INTEGER,
  updated_at INTEGER
, sort_order INTEGER DEFAULT 0, is_active INTEGER DEFAULT 1, form_fields TEXT);
CREATE TABLE listings (
  id TEXT PRIMARY KEY,
  title TEXT NOT NULL,
  slug TEXT NOT NULL UNIQUE,
  owner_id TEXT NOT NULL,
  category_id TEXT,
  status TEXT DEFAULT 'draft',
  description TEXT NOT NULL,
  condition TEXT,
  location TEXT,
  contact_name TEXT,
  contact_number TEXT,
  country_code TEXT DEFAULT '+670',
  email TEXT,
  image_ids TEXT,
  tags TEXT,
  likes INTEGER DEFAULT 0,
  saves INTEGER DEFAULT 0,
  views INTEGER DEFAULT 0,
  created_at INTEGER,
  updated_at INTEGER,
  expires_at INTEGER
, location_lat REAL, location_lng REAL, last_renewed_at INTEGER, featured INTEGER DEFAULT 0, featured_until INTEGER, price_amount REAL, price_unit TEXT, extra_data TEXT);
CREATE TABLE saved_items (
  id TEXT PRIMARY KEY NOT NULL,
  user_id TEXT NOT NULL,
  type TEXT NOT NULL,
  type_id TEXT NOT NULL,
  created_at INTEGER
);
CREATE TABLE reviews (
  id TEXT PRIMARY KEY NOT NULL,
  business_id TEXT NOT NULL,
  user_id TEXT NOT NULL,
  rating INTEGER NOT NULL,
  title TEXT,
  content TEXT,
  reply TEXT,
  replied_at INTEGER,
  replied_by TEXT,
  is_edited INTEGER DEFAULT 0,
  status TEXT DEFAULT 'pending',
  created_at INTEGER,
  updated_at INTEGER
);
CREATE TABLE blog_categories (
  id TEXT PRIMARY KEY NOT NULL,
  name TEXT NOT NULL,
  slug TEXT NOT NULL UNIQUE,
  description TEXT,
  icon TEXT,
  parent_id TEXT,
  sort_order INTEGER DEFAULT 0,
  is_active INTEGER DEFAULT 1,
  created_at INTEGER,
  updated_at INTEGER
);
CREATE TABLE product_categories (
  id TEXT PRIMARY KEY NOT NULL,
  name TEXT NOT NULL,
  slug TEXT NOT NULL UNIQUE,
  description TEXT,
  icon TEXT,
  parent_id TEXT,
  sort_order INTEGER DEFAULT 0,
  is_active INTEGER DEFAULT 1,
  form_fields TEXT,
  created_at INTEGER,
  updated_at INTEGER
, default_attributes TEXT);
CREATE TABLE orders (
  id TEXT PRIMARY KEY NOT NULL,
  service_package_id TEXT,
  variant_snapshot TEXT,
  type TEXT,
  type_id TEXT,
  user_id TEXT,
  amount INTEGER DEFAULT 0,
  status TEXT DEFAULT 'pending',
  payment_method TEXT,
  paid_date INTEGER,
  expires_at INTEGER,
  admin_notes TEXT,
  created_at INTEGER,
  updated_at INTEGER
);
CREATE TABLE IF NOT EXISTS "ad_banners" (
  id TEXT PRIMARY KEY NOT NULL,
  title TEXT NOT NULL,
  description TEXT,
  image_id TEXT,
  link_url TEXT,
  link_type TEXT NOT NULL DEFAULT 'business',
  position TEXT NOT NULL DEFAULT 'homepage',
  sort_order INTEGER DEFAULT 0,
  order_id TEXT,
  is_active INTEGER DEFAULT 1,
  start_date INTEGER,
  end_date INTEGER,
  created_at INTEGER,
  updated_at INTEGER
);
CREATE TABLE service_packages (
  id TEXT PRIMARY KEY NOT NULL,
  name TEXT NOT NULL,
  slug TEXT NOT NULL UNIQUE,
  type TEXT NOT NULL,                    -- 'subscription' | 'listing_renewal' | 'featured' | 'addon'
  category TEXT,                          -- 'business' | 'listing' | 'other'
  description TEXT,
  variants TEXT NOT NULL,                -- JSON: [{ name, price, currency, durationValue, durationUnit, limits, features }]
  is_active INTEGER DEFAULT 1,
  sort_order INTEGER DEFAULT 0,
  created_at INTEGER,
  updated_at INTEGER
);
CREATE TABLE IF NOT EXISTS "products" (
  id TEXT PRIMARY KEY NOT NULL,
  title TEXT NOT NULL,
  description TEXT,
  specifications TEXT,
  featured INTEGER DEFAULT 0,
  active INTEGER DEFAULT 1,
  created_at INTEGER DEFAULT (strftime('%s', 'now')),
  updated_at INTEGER DEFAULT (strftime('%s', 'now')),
  business_id TEXT,
  category_id TEXT,
  images TEXT
, slug TEXT, sort_order INTEGER DEFAULT 0, product_type TEXT DEFAULT 'product', price_amount REAL, price_unit TEXT);
CREATE TABLE media (
  id TEXT PRIMARY KEY NOT NULL,
  r2_key TEXT NOT NULL UNIQUE,
  filename TEXT NOT NULL,
  mime_type TEXT NOT NULL,
  size INTEGER NOT NULL,
  width INTEGER,
  height INTEGER,
  sort_order INTEGER DEFAULT 0,
  alt TEXT,
  hash TEXT UNIQUE,
  created_by_id TEXT,
  created_at INTEGER,
  url TEXT NOT NULL DEFAULT '', type TEXT NOT NULL DEFAULT '', type_id TEXT NOT NULL DEFAULT '', entity_type TEXT, entity_id TEXT, purpose TEXT);
CREATE TABLE blog_posts (id TEXT PRIMARY KEY, title TEXT NOT NULL, slug TEXT NOT NULL UNIQUE, excerpt TEXT, content TEXT, cover_image_id TEXT, author_id TEXT, author_name TEXT, status TEXT DEFAULT 'draft', tags TEXT, meta_title TEXT, meta_description TEXT, canonical_url TEXT, published_at INTEGER, created_at INTEGER, updated_at INTEGER);
CREATE TABLE plans (id TEXT PRIMARY KEY NOT NULL, name TEXT NOT NULL, slug TEXT NOT NULL UNIQUE, type TEXT NOT NULL, description TEXT, price REAL NOT NULL, currency TEXT DEFAULT 'USD', interval TEXT DEFAULT 'monthly', features TEXT, limits TEXT, is_active INTEGER DEFAULT 1, sort_order INTEGER DEFAULT 0, created_at INTEGER, updated_at INTEGER);
CREATE TABLE `latest_update` (
  `id` text PRIMARY KEY NOT NULL,
  `type` text NOT NULL,
  `type_id` text NOT NULL,
  `content` text NOT NULL,
  `image_ids` text,
  `video_id` text,
  `created_at` integer,
  `updated_at` integer
);
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX `categories_slug_unique` ON "business_categories" (`slug`);
CREATE UNIQUE INDEX `site_settings_key_unique` ON `site_settings` (`key`);
CREATE INDEX categories_parent_idx ON "business_categories" ('parent_id');
CREATE INDEX categories_entity_type_idx ON "business_categories" ('entity_type');
CREATE INDEX users_role_idx ON 'users' ('role');
CREATE INDEX sessions_user_idx ON 'sessions' ('user_id');
CREATE INDEX accounts_user_idx ON 'accounts' ('user_id');
CREATE INDEX verifications_expires_idx ON 'verifications' ('expires_at');
CREATE INDEX saved_items_user_idx ON saved_items(user_id);
CREATE INDEX saved_items_type_idx ON saved_items(type);
CREATE INDEX saved_items_type_id_idx ON saved_items(type_id);
CREATE UNIQUE INDEX saved_items_user_type_typeId_idx ON saved_items(user_id, type, type_id);
CREATE INDEX reviews_status_idx ON reviews(status);
CREATE INDEX orders_user_idx ON orders(user_id);
CREATE INDEX orders_status_idx ON orders(status);
CREATE UNIQUE INDEX ad_banners_id_idx ON "ad_banners"(id);
CREATE INDEX ad_banners_position_idx ON "ad_banners"(position);
CREATE INDEX ad_banners_order_idx ON "ad_banners"(order_id);
CREATE UNIQUE INDEX service_packages_slug_idx ON service_packages(slug);
CREATE INDEX service_packages_type_idx ON service_packages(type);
CREATE INDEX service_packages_category_idx ON service_packages(category);
CREATE INDEX service_packages_active_idx ON service_packages(is_active);
CREATE UNIQUE INDEX sessions_token_idx ON sessions(token);
CREATE UNIQUE INDEX users_email_idx ON users(email);
CREATE UNIQUE INDEX listings_slug_idx ON listings(slug);
CREATE INDEX listings_owner_idx ON listings(owner_id);
CREATE INDEX listings_status_idx ON listings(status);
CREATE INDEX listings_category_idx ON listings(category_id);
CREATE INDEX listings_featured_idx ON listings(featured);
CREATE INDEX listings_expires_idx ON listings(expires_at);
CREATE UNIQUE INDEX businesses_slug_idx ON businesses(slug);
CREATE INDEX businesses_owner_idx ON businesses(owner_id);
CREATE INDEX businesses_status_idx ON businesses(status);
CREATE INDEX businesses_category_idx ON businesses(category_id);
CREATE UNIQUE INDEX non_profits_slug_idx ON non_profits(slug);
CREATE INDEX non_profits_owner_idx ON non_profits(owner_id);
CREATE INDEX non_profits_status_idx ON non_profits(status);
CREATE INDEX non_profits_category_idx ON non_profits(category_id);
CREATE UNIQUE INDEX public_sectors_slug_idx ON public_sectors(slug);
CREATE INDEX public_sectors_owner_idx ON public_sectors(owner_id);
CREATE INDEX public_sectors_status_idx ON public_sectors(status);
CREATE INDEX public_sectors_category_idx ON public_sectors(category_id);
CREATE UNIQUE INDEX products_slug_idx ON products(slug);
CREATE INDEX products_business_idx ON products(business_id);
CREATE INDEX products_category_idx ON products(category_id);
CREATE INDEX products_active_idx ON products(active);
CREATE UNIQUE INDEX blog_categories_slug_idx ON blog_categories(slug);
CREATE INDEX ad_banners_active_idx ON ad_banners(is_active);
CREATE INDEX orders_service_package_idx ON orders(service_package_id);
CREATE INDEX orders_type_idx ON orders(type);
CREATE INDEX orders_type_id_idx ON orders(type_id);
CREATE INDEX reviews_business_idx ON reviews(business_id);
CREATE INDEX reviews_user_idx ON reviews(user_id);
CREATE UNIQUE INDEX reviews_user_business_idx ON reviews(user_id, business_id);
CREATE UNIQUE INDEX product_categories_slug_idx ON product_categories(slug);
CREATE INDEX product_categories_parent_idx ON product_categories(parent_id);
CREATE UNIQUE INDEX listing_categories_slug_idx ON listing_categories(slug);
CREATE INDEX listing_categories_parent_idx ON listing_categories(parent_id);
CREATE INDEX blog_posts_status_idx ON blog_posts(status);
CREATE UNIQUE INDEX site_settings_key_idx ON site_settings(key);
CREATE UNIQUE INDEX `latest_update_unique` ON `latest_update` (`type`, `type_id`);
CREATE INDEX `latest_update_type_idx` ON `latest_update` (`type`);
CREATE INDEX `latest_update_type_id_idx` ON `latest_update` (`type_id`);
CREATE INDEX reviews_replied_by_idx ON reviews(replied_by);
CREATE UNIQUE INDEX media_entity_purpose_idx ON media(entity_type, entity_id, purpose);
